phase('Attribution')
const jobs = []
for (let i = 0; i < 21; i++) {
  const nn = `surge_${String(i).padStart(2, '0')}`
  jobs.push(() => agent(
    SURGE_TASK.replace('{n}', '8').replace('{data}', JSON.stringify(PACKS[nn])),
    { label: `attr:${nn}`, schema: SCHEMA, model: 'opus', effort: 'max' },
  ).then(v => v && { ...v, batch: nn }))
}
for (let i = 0; i < 7; i++) {
  const nn = `control_${String(i).padStart(2, '0')}`
  jobs.push(() => agent(
    CTRL_TASK.replace('{n}', '8').replace('{data}', JSON.stringify(PACKS[nn])),
    { label: `attr:${nn}`, schema: SCHEMA, model: 'opus', effort: 'max' },
  ).then(v => v && { ...v, batch: nn }))
}
const reports = (await parallel(jobs)).filter(Boolean)
log(`歸因完成 ${reports.length}/28`)
phase('Synthesis')
const phil = await agent(SYNTH.replace('{reports}', JSON.stringify(reports)),
  { label: 'synthesis', schema: PHIL_SCHEMA, model: 'opus', effort: 'max' })
return { reports, phil }
